The code below creates a complete, self-contained HTML file. It uses **Three.js** to render a 3D scene containing a house.

### How to use this:
1.  Copy the code block below.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Scene</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Scene - Use Mouse to Rotate/Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. Scene Setup ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // --- 2. Controls ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // --- 3. Lighting ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 4. Building the House ---

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, emissive: 0x87CEEB, emissiveIntensity: 0.5 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5C4033 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // Group to hold the house
        const houseGroup = new THREE.Group();

        // A. The Floor (Ground)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // B. The Main Body
        const bodyGeo = new THREE.BoxGeometry(10, 6, 10);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3; // Sit on top of ground
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // C. The Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(9, 4, 4); // 4 sides
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8; // Sit on top of body
        roof.rotation.y = Math.PI / 4; // Align square base with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // D. Windows
        function createWindow(x, y, z, w, h) {
            const winGeo = new THREE.BoxGeometry(w, h, 0.5);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }

        // Front Windows
        createWindow(-2.5, 4, 5, 2, 2);
        createWindow(2.5, 4, 5, 2, 2);
        // Side Window
        createWindow(0, 4, -5, 2, 2);

        // E. The Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.6);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 5);
        door.castShadow = true;
        houseGroup.add(door);

        // F. Chimney
        const chimneyGeo = new THREE.BoxGeometry(1.5, 3, 1.5);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(4, 9, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        // Add house to scene
        scene.add(houseGroup);

        // --- 5. Animation Loop ---
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Imports Three.js:** It pulls the library directly from a CDN (unpkg), so you don't need to install anything.
2.  **Sets up the Scene:** Creates a sky-blue background, a ground plane, and lighting (ambient + directional with shadows).
3.  **Constructs the House:**
    *   **Body:** A white box.
    *   **Roof:** A brown cone rotated to look like a pyramid.
    *   **Details:** Adds blue windows, a brown door, and a chimney using simple geometry primitives.
4.  **Interactivity:** Adds `OrbitControls`, allowing you to click and drag to rotate around the house, or scroll to zoom in/out.
5.  **Responsiveness:** Automatically adjusts the canvas size if you resize your browser window.
